def argmax_first_index(values):
    if not values:raise ValueError("empty")
    return max(range(len(values)),key=values.__getitem__)

def inclusive_integer_range(start,stop,step=1):
    if step==0:raise ValueError("zero step")
    end=stop+(1 if step>0 else -1)
    return list(range(start,end,step))

